﻿@page "/"
@rendermode InteractiveServer
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Services
@using VetClinic.Data.Models

@inject PatientService PatientService
@inject AppointmentService AppointmentService
@inject BillingService BillingService

<PageTitle>VetClinic Dashboard</PageTitle>

<h1 class="mb-4">🐾 Clinic Dashboard</h1>

@if (loading)
{
    <p>Loading dashboard...</p>
}
else
{
    <div class="row g-3 mb-4">
        <div class="col-md-3">
            <div class="card text-bg-primary">
                <div class="card-body">
                    <h5 class="card-title">Patients</h5>
                    <p class="card-text display-6">@petCount</p>
                    <a href="patients" class="text-white">Manage patients →</a>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-info">
                <div class="card-body">
                    <h5 class="card-title">Today's Appointments</h5>
                    <p class="card-text display-6">@todayAppointments</p>
                    <a href="appointments" class="text-white">View calendar →</a>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-warning">
                <div class="card-body">
                    <h5 class="card-title">Pending Invoices</h5>
                    <p class="card-text display-6">@pendingInvoices</p>
                    <a href="billing" class="text-white">View billing →</a>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-success">
                <div class="card-body">
                    <h5 class="card-title">This Week</h5>
                    <p class="card-text display-6">@weekAppointments</p>
                    <small class="text-white">appointments scheduled</small>
                </div>
            </div>
        </div>
    </div>

    <div class="row g-3">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Today's Schedule</strong>
                    <a href="appointments" class="btn btn-sm btn-outline-primary">Full Calendar</a>
                </div>
                <div class="card-body">
                    @if (todayAppts.Count == 0)
                    {
                        <p class="text-muted">No appointments today.</p>
                    }
                    else
                    {
                        <table class="table table-sm">
                            <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th><th>Status</th></tr></thead>
                            <tbody>
                                @foreach (var a in todayAppts)
                                {
                                    <tr>
                                        <td>@a.StartTime.ToString("h:mm tt")</td>
                                        <td>@a.Pet.Name</td>
                                        <td>@a.Reason</td>
                                        <td>@a.Veterinarian</td>
                                        <td>
                                            <span class="badge bg-@(a.Status == AppointmentStatus.Scheduled ? "primary" : a.Status == AppointmentStatus.Completed ? "success" : "secondary")">
                                                @a.Status
                                            </span>
                                        </td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    }
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Quick Actions</strong>
                </div>
                <div class="card-body">
                    <div class="d-grid gap-2">
                        <a href="patients" class="btn btn-outline-primary">Register New Patient</a>
                        <a href="appointments" class="btn btn-outline-info">Schedule Appointment</a>
                        <a href="billing" class="btn btn-outline-warning">Create Invoice</a>
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool loading = true;
    private int petCount;
    private int todayAppointments;
    private int weekAppointments;
    private int pendingInvoices;
    private List<Appointment> todayAppts = [];

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        var weekStart = today.AddDays(-(int)today.DayOfWeek + (int)DayOfWeek.Monday);
        if (today.DayOfWeek == DayOfWeek.Sunday) weekStart = weekStart.AddDays(-7);
        var weekEnd = weekStart.AddDays(7);

        var pets = await PatientService.GetPetsAsync(null);
        petCount = pets.Count;

        todayAppts = await AppointmentService.GetAppointmentsAsync(today, today.AddDays(1));
        todayAppointments = todayAppts.Count(a => a.Status != AppointmentStatus.Cancelled);

        var weekAppts = await AppointmentService.GetAppointmentsAsync(weekStart, weekEnd);
        weekAppointments = weekAppts.Count(a => a.Status != AppointmentStatus.Cancelled);

        var invoices = await BillingService.GetInvoicesAsync(null, InvoiceStatus.Pending);
        pendingInvoices = invoices.Count;

        todayAppts = todayAppts.Where(a => a.Status != AppointmentStatus.Cancelled).OrderBy(a => a.StartTime).ToList();
        loading = false;
    }
}

