using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class PatientService(ApplicationDbContext db)
{
    public async Task<List<Owner>> GetOwnersAsync(string? search = null)
    {
        var query = db.Owners.Include(o => o.Pets).AsQueryable();

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLower();
            query = query.Where(o =>
                o.FirstName.ToLower().Contains(term) ||
                o.LastName.ToLower().Contains(term) ||
                o.Phone.Contains(term));
        }

        return await query.OrderBy(o => o.LastName).ThenBy(o => o.FirstName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerAsync(int id)
    {
        return await db.Owners
            .Include(o => o.Pets)
            .FirstOrDefaultAsync(o => o.Id == id);
    }

    public async Task SaveOwnerAsync(Owner owner)
    {
        if (owner.Id == 0)
            db.Owners.Add(owner);
        else
            db.Owners.Update(owner);

        await db.SaveChangesAsync();
    }

    public async Task DeleteOwnerAsync(int id)
    {
        var owner = await db.Owners.FindAsync(id);
        if (owner is not null)
        {
            db.Owners.Remove(owner);
            await db.SaveChangesAsync();
        }
    }

    public async Task<Pet?> GetPetAsync(int id)
    {
        return await db.Pets
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .Include(p => p.Appointments)
            .FirstOrDefaultAsync(p => p.Id == id);
    }

    public async Task<List<Pet>> GetPetsAsync(string? search = null)
    {
        var query = db.Pets.Include(p => p.Owner).AsQueryable();

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLower();
            query = query.Where(p =>
                p.Name.ToLower().Contains(term) ||
                p.Owner.FirstName.ToLower().Contains(term) ||
                p.Owner.LastName.ToLower().Contains(term));
        }

        return await query.OrderBy(p => p.Name).ToListAsync();
    }

    public async Task SavePetAsync(Pet pet)
    {
        if (pet.Id == 0)
            db.Pets.Add(pet);
        else
            db.Pets.Update(pet);

        await db.SaveChangesAsync();
    }

    public async Task DeletePetAsync(int id)
    {
        var pet = await db.Pets.FindAsync(id);
        if (pet is not null)
        {
            db.Pets.Remove(pet);
            await db.SaveChangesAsync();
        }
    }

    public async Task<List<TreatmentNote>> GetTreatmentNotesAsync(int petId)
    {
        return await db.TreatmentNotes
            .Where(t => t.PetId == petId)
            .OrderByDescending(t => t.Date)
            .ToListAsync();
    }

    public async Task SaveTreatmentNoteAsync(TreatmentNote note)
    {
        if (note.Id == 0)
            db.TreatmentNotes.Add(note);
        else
            db.TreatmentNotes.Update(note);

        await db.SaveChangesAsync();
