     {
         var apptEnd = appt.StartTime.AddMinutes(appt.DurationMinutes);

         var conflict = await db.Appointments
             .Where(a => a.Id != appt.Id)
             .Where(a => a.Veterinarian == appt.Veterinarian)
             .Where(a => a.Status != AppointmentStatus.Cancelled)
             .Where(a => a.StartTime < apptEnd &&
                         EF.Functions.DateDiffMinute(a.StartTime, appt.StartTime) < a.DurationMinutes == false)
             .AnyAsync();

         // Manual overlap check: existing.StartTime < appt.EndTime && appt.StartTime < existing.EndTime
         // existing.EndTime = existing.StartTime + existing.DurationMinutes (computed, not in DB)
         // We must compute it in the query.
         conflict = await db.Appointments
             .Where(a => a.Id != appt.Id)
             .Where(a => a.Veterinarian == appt.Veterinarian)
             .Where(a => a.Status != AppointmentStatus.Cancelled)
             .AnyAsync(a =>
                 a.StartTime < apptEnd &&
                 appt.StartTime < a.StartTime.AddMinutes(a.DurationMinutes));

         if (conflict)
             throw new InvalidOperationException(
                 "This appointment conflicts with an existing appointment for the same veterinarian.");

         if (appt.Id == 0)
             db.Appointments.Add(appt);
         else
             db.Appointments.Update(appt);

         await db.SaveChangesAsync();
     }

     public async Task CancelAppointmentAsync(int id)
     {
         var appt = await db.Appointments.FindAsync(id);
         if (appt is not null)
         {
             appt.Status = AppointmentStatus.Cancelled;
             await db.SaveChangesAsync();
         }
     }

     public async Task<List<DateTime>> GetAvailableSlotsAsync(DateTime date, string veterinarian, int durationMinutes = 30)
     {
         var dayStart = date.Date.AddHours(8);
         var dayEnd = date.Date.AddHours(17);

         var existingAppointments = await db.Appointments
             .Where(a => a.Veterinarian == veterinarian)
             .Where(a => a.Status != AppointmentStatus.Cancelled)
             .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd)
             .ToListAsync();

         var slots = new List<DateTime>();
         for (var slot = dayStart; slot.AddMinutes(durationMinutes) <= dayEnd; slot = slot.AddMinutes(30))
         {
             var slotEnd = slot.AddMinutes(durationMinutes);
             var hasConflict = existingAppointments.Any(a =>
                 a.StartTime < slotEnd && slot < a.StartTime.AddMinutes(a.DurationMinutes));

             if (!hasConflict)
                 slots.Add(slot);
         }

         return slots;
     }

     public async Task<List<string>> GetVeterinariansAsync()
     {
         var vets = await db.Appointments
             .Select(a => a.Veterinarian)
             .Distinct()
             .OrderBy(v => v)
             .ToListAsync();

         return vets.Count > 0
             ? vets
             : ["Dr. Smith", "Dr. Johnson", "Dr. Williams"];
     }
 }

