 using Microsoft.EntityFrameworkCore;
 using VetClinic.Data;
 using VetClinic.Data.Models;

 namespace VetClinic.Services;

 public class BillingService(ApplicationDbContext db)
 {
     public async Task<List<Invoice>> GetInvoicesAsync(string? search = null, InvoiceStatus? status = null)
     {
         var query = db.Invoices
             .Include(i => i.Pet).ThenInclude(p => p.Owner)
             .Include(i => i.Items)
             .Include(i => i.Payments)
             .AsQueryable();

         if (status.HasValue)
             query = query.Where(i => i.Status == status.Value);

         if (!string.IsNullOrWhiteSpace(search))
         {
             var term = search.Trim().ToLower();
             query = query.Where(i =>
                 i.InvoiceNumber.ToLower().Contains(term) ||
                 i.Pet.Name.ToLower().Contains(term) ||
                 i.Pet.Owner.FirstName.ToLower().Contains(term) ||
                 i.Pet.Owner.LastName.ToLower().Contains(term));
         }

         return await query.OrderByDescending(i => i.CreatedDate).ToListAsync();
     }

     public async Task<Invoice?> GetInvoiceAsync(int id)
     {
         return await db.Invoices
             .Include(i => i.Pet).ThenInclude(p => p.Owner)
             .Include(i => i.Items)
             .Include(i => i.Payments)
             .FirstOrDefaultAsync(i => i.Id == id);
     }

     public async Task CreateInvoiceAsync(Invoice invoice)
     {
         var random = new Random();
         invoice.InvoiceNumber = $"INV-{DateTime.UtcNow:yyyyMMddHHmmss}{random.Next(100, 999)}";
         invoice.CreatedDate = DateTime.UtcNow;
         invoice.DueDate = invoice.CreatedDate.AddDays(30);

         db.Invoices.Add(invoice);
         await db.SaveChangesAsync();
     }

     public async Task UpdateInvoiceAsync(Invoice invoice)
     {
         db.Invoices.Update(invoice);
         await db.SaveChangesAsync();
     }

     public async Task AddInvoiceItemAsync(InvoiceItem item)
     {
         db.InvoiceItems.Add(item);
         await db.SaveChangesAsync();
     }

     public async Task RemoveInvoiceItemAsync(int itemId)
     {
         var item = await db.InvoiceItems.FindAsync(itemId);
         if (item is not null)
         {
             db.InvoiceItems.Remove(item);
             await db.SaveChangesAsync();
         }
     }

     public async Task ProcessPaymentAsync(Payment payment)
     {
         payment.Date = DateTime.UtcNow;
         db.Payments.Add(payment);
         await db.SaveChangesAsync();

         var invoice = await db.Invoices
             .Include(i => i.Items)
             .Include(i => i.Payments)
             .FirstOrDefaultAsync(i => i.Id == payment.InvoiceId);

         if (invoice is not null && invoice.Balance <= 0)
         {
             invoice.Status = InvoiceStatus.Paid;
             await db.SaveChangesAsync();
         }
     }

     public async Task<List<Payment>> GetPaymentHistoryAsync(int? invoiceId = null)
     {
         var query = db.Payments
             .Include(p => p.Invoice).ThenInclude(i => i.Pet).ThenInclude(p => p.Owner)
             .AsQueryable();

         if (invoiceId.HasValue)
             query = query.Where(p => p.InvoiceId == invoiceId.Value);

         return await query.OrderByDescending(p => p.Date).ToListAsync();
     }
 }

