@page "/patients"
@rendermode InteractiveServer
@attribute [Authorize]
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@inject PatientService PatientService
@inject NavigationManager Nav

<PageTitle>Patients</PageTitle>

<h2 class="mb-3">Patients</h2>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search owners or pets by name..."
           @bind="searchTerm" @bind:event="oninput" @bind:after="SearchAsync" />
</div>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "owners" ? "active" : "")" @onclick='() => activeTab = "owners"'>Owners</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "pets" ? "active" : "")" @onclick='() => activeTab = "pets"'>Pets</button>
    </li>
</ul>

@if (activeTab == "owners")
{
    <div class="mb-3">
        <button class="btn btn-primary btn-sm" @onclick="ToggleOwnerForm">
            @(showOwnerForm ? "Cancel" : "Add Owner")
        </button>
    </div>

    @if (showOwnerForm)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5 class="card-title">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</h5>
                <EditForm Model="editingOwner" OnValidSubmit="SaveOwnerAsync" FormName="ownerForm">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />
                    <div class="row g-2">
                        <div class="col-md-6">
                            <label class="form-label">First Name</label>
                            <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Last Name</label>
                            <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Phone</label>
                            <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Email</label>
                            <InputText class="form-control" @bind-Value="editingOwner.Email" />
                        </div>
                        <div class="col-12">
                            <label class="form-label">Address</label>
                            <InputText class="form-control" @bind-Value="editingOwner.Address" />
                        </div>
                        <div class="col-12">
                            <button type="submit" class="btn btn-success btn-sm me-1">Save</button>
                            <button type="button" class="btn btn-secondary btn-sm" @onclick="ToggleOwnerForm">Cancel</button>
                        </div>
                    </div>
                </EditForm>
            </div>
        </div>
    }

    @if (owners == null)
    {
        <p>Loading...</p>
    }
    else
    {
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>First Name</th>
                    <th>Last Name</th>
                    <th>Phone</th>
                    <th>Email</th>
                    <th># Pets</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var owner in owners)
                {
                    <tr>
                        <td>@owner.FirstName</td>
                        <td>@owner.LastName</td>
                        <td>@owner.Phone</td>
                        <td>@owner.Email</td>
                        <td>@owner.Pets.Count</td>
                        <td>
                            <a href="/patients/owners/@owner.Id" class="btn btn-outline-info btn-sm me-1">View</a>
                            <button class="btn btn-outline-primary btn-sm me-1" @onclick="() => EditOwner(owner)">Edit</button>
                            @if (deleteConfirmOwnerId == owner.Id)
                            {
                                <button class="btn btn-danger btn-sm" @onclick="() => DeleteOwnerAsync(owner.Id)">Confirm?</button>
                            }
                            else
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => deleteConfirmOwnerId = owner.Id">Delete</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }
}
else
{
    <div class="mb-3">
        <button class="btn btn-primary btn-sm" @onclick="TogglePetForm">
            @(showPetForm ? "Cancel" : "Register Pet")
        </button>
    </div>

    @if (showPetForm)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5 class="card-title">@(editingPet.Id == 0 ? "Register Pet" : "Edit Pet")</h5>
                <EditForm Model="editingPet" OnValidSubmit="SavePetAsync" FormName="petForm">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />
                    <div class="row g-2">
                        <div class="col-md-6">
                            <label class="form-label">Name</label>
                            <InputText class="form-control" @bind-Value="editingPet.Name" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Species</label>
                            <InputText class="form-control" @bind-Value="editingPet.Species" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Breed</label>
                            <InputText class="form-control" @bind-Value="editingPet.Breed" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Date of Birth</label>
                            <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Weight (kg)</label>
                            <InputNumber class="form-control" @bind-Value="editingPet.WeightKg" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Color</label>
                            <InputText class="form-control" @bind-Value="editingPet.Color" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Sex</label>
                            <InputText class="form-control" @bind-Value="editingPet.Sex" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Microchip ID</label>
                            <InputText class="form-control" @bind-Value="editingPet.MicrochipId" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Owner</label>
                            <InputSelect class="form-select" @bind-Value="editingPet.OwnerId">
                                <option value="0">-- Select Owner --</option>
                                @if (allOwners != null)
                                {
                                    @foreach (var o in allOwners)
                                    {
                                        <option value="@o.Id">@o.FullName</option>
                                    }
                                }
                            </InputSelect>
                        </div>
                        <div class="col-12">
                            <button type="submit" class="btn btn-success btn-sm me-1">Save</button>
                            <button type="button" class="btn btn-secondary btn-sm" @onclick="TogglePetForm">Cancel</button>
                        </div>
                    </div>
                </EditForm>
            </div>
        </div>
    }

    @if (pets == null)
    {
        <p>Loading...</p>
    }
    else
    {
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Name</th>
                    <th>Species</th>
                    <th>Breed</th>
                    <th>Owner</th>
                    <th>Age</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var pet in pets)
                {
                    <tr>
                        <td>@pet.Name</td>
                        <td>@pet.Species</td>
                        <td>@pet.Breed</td>
                        <td><a href="/patients/owners/@pet.OwnerId">@pet.Owner?.FullName</a></td>
                        <td>@CalculateAge(pet.DateOfBirth)</td>
                        <td>
                            <a href="/patients/pets/@pet.Id" class="btn btn-outline-info btn-sm me-1">View</a>
                            <button class="btn btn-outline-primary btn-sm me-1" @onclick="() => EditPet(pet)">Edit</button>
                            @if (deleteConfirmPetId == pet.Id)
                            {
                                <button class="btn btn-danger btn-sm" @onclick="() => DeletePetAsync(pet.Id)">Confirm?</button>
                            }
                            else
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => deleteConfirmPetId = pet.Id">Delete</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    private string activeTab = "owners";
    private string? searchTerm;

    private List<Owner>? owners;
    private List<Pet>? pets;
    private List<Owner>? allOwners;

    private bool showOwnerForm;
    private bool showPetForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();

    private int? deleteConfirmOwnerId;
    private int? deleteConfirmPetId;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        owners = await PatientService.GetOwnersAsync(searchTerm);
        pets = await PatientService.GetPetsAsync(searchTerm);
        allOwners = await PatientService.GetOwnersAsync(null);
    }

    private async Task SearchAsync()
    {
        await LoadDataAsync();
    }

    private void ToggleOwnerForm()
    {
        showOwnerForm = !showOwnerForm;
        if (!showOwnerForm) editingOwner = new();
    }

    private void TogglePetForm()
    {
        showPetForm = !showPetForm;
        if (!showPetForm) editingPet = new();
    }

    private void EditOwner(Owner owner)
    {
        editingOwner = new Owner
        {
            Id = owner.Id,
            FirstName = owner.FirstName,
            LastName = owner.LastName,
            Phone = owner.Phone,
            Email = owner.Email,
            Address = owner.Address
        };
        showOwnerForm = true;
    }

    private void EditPet(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id,
            Name = pet.Name,
            Species = pet.Species,
            Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth,
            WeightKg = pet.WeightKg,
            Color = pet.Color,
            Sex = pet.Sex,
            MicrochipId = pet.MicrochipId,
            OwnerId = pet.OwnerId
        };
        showPetForm = true;
    }

    private async Task SaveOwnerAsync()
    {
        await PatientService.SaveOwnerAsync(editingOwner);
        editingOwner = new();
        showOwnerForm = false;
        deleteConfirmOwnerId = null;
        await LoadDataAsync();
    }

    private async Task SavePetAsync()
    {
        await PatientService.SavePetAsync(editingPet);
        editingPet = new();
        showPetForm = false;
        deleteConfirmPetId = null;
        await LoadDataAsync();
    }

    private async Task DeleteOwnerAsync(int id)
    {
        await PatientService.DeleteOwnerAsync(id);
        deleteConfirmOwnerId = null;
        await LoadDataAsync();
    }

    private async Task DeletePetAsync(int id)
    {
        await PatientService.DeletePetAsync(id);
        deleteConfirmPetId = null;
        await LoadDataAsync();
    }

    private string CalculateAge(DateOnly? dob)
    {
        if (dob is null) return "—";
        var today = DateOnly.FromDateTime(DateTime.Today);
        var age = today.Year - dob.Value.Year;
        if (dob.Value.AddYears(age) > today) age--;
        return age < 1 ? "< 1 yr" : $"{age} yr";
    }
}

