@code {
    private string activeTab = "owners";
    private string? searchTerm;

    private List<Owner>? owners;
    private List<Pet>? pets;
    private List<Owner>? allOwners;

    private bool showOwnerForm;
    private bool showPetForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();

    private int? deleteConfirmOwnerId;
    private int? deleteConfirmPetId;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        owners = await PatientService.GetOwnersAsync(searchTerm);
        pets = await PatientService.GetPetsAsync(searchTerm);
        allOwners = await PatientService.GetOwnersAsync(null);
    }

    private async Task SearchAsync()
    {
        await LoadDataAsync();
    }

    private void ToggleOwnerForm()
    {
        showOwnerForm = !showOwnerForm;
        if (!showOwnerForm) editingOwner = new();
    }

    private void TogglePetForm()
    {
        showPetForm = !showPetForm;
        if (!showPetForm) editingPet = new();
    }

    private void EditOwner(Owner owner)
    {
        editingOwner = new Owner
        {
            Id = owner.Id,
            FirstName = owner.FirstName,
            LastName = owner.LastName,
            Phone = owner.Phone,
            Email = owner.Email,
            Address = owner.Address
        };
        showOwnerForm = true;
    }

    private void EditPet(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id,
            Name = pet.Name,
            Species = pet.Species,
            Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth,
            WeightKg = pet.WeightKg,
            Color = pet.Color,
            Sex = pet.Sex,
            MicrochipId = pet.MicrochipId,
            OwnerId = pet.OwnerId
        };
        showPetForm = true;
    }

    private async Task SaveOwnerAsync()
    {
        await PatientService.SaveOwnerAsync(editingOwner);
        editingOwner = new();
        showOwnerForm = false;
        deleteConfirmOwnerId = null;
        await LoadDataAsync();
    }

    private async Task SavePetAsync()
    {
        await PatientService.SavePetAsync(editingPet);
        editingPet = new();
        showPetForm = false;
        deleteConfirmPetId = null;
        await LoadDataAsync();
    }

    private async Task DeleteOwnerAsync(int id)
    {
        await PatientService.DeleteOwnerAsync(id);
        deleteConfirmOwnerId = null;
        await LoadDataAsync();
    }

    private async Task DeletePetAsync(int id)
    {
        await PatientService.DeletePetAsync(id);
        deleteConfirmPetId = null;
        await LoadDataAsync();
    }

    private string CalculateAge(DateOnly? dob)
    {
        if (dob is null) return "—";
        var today = DateOnly.FromDateTime(DateTime.Today);
        var age = today.Year - dob.Value.Year;
        if (dob.Value.AddYears(age) > today) age--;
        return age < 1 ? "< 1 yr" : $"{age} yr";
    }
}

