@code {
    [Parameter]
    public int Id { get; set; }

    private Pet? pet;
    private List<TreatmentNote>? treatmentNotes;

    private bool editMode;
    private Pet editingPet = new();

    private bool showNoteForm;
    private TreatmentNote editingNote = new();
    private int? editingNoteId;
    private int? deleteConfirmNoteId;
    private HashSet<int> expandedNoteIds = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        pet = await PatientService.GetPetAsync(Id);
        treatmentNotes = await PatientService.GetTreatmentNotesAsync(Id);
    }

    private void CancelEdit()
    {
        editMode = false;
        editingPet = new();
    }

    private async Task SavePetAsync()
    {
        editingPet.OwnerId = pet!.OwnerId;
        await PatientService.SavePetAsync(editingPet);
        editMode = false;
        await LoadAsync();
    }

    private void ToggleNoteForm()
    {
        showNoteForm = !showNoteForm;
        editingNoteId = null;
        if (showNoteForm)
        {
            editingNote = new TreatmentNote { PetId = Id, Date = DateTime.UtcNow };
        }
        else
        {
            editingNote = new();
        }
    }

    private void EditNote(TreatmentNote note)
    {
        editingNoteId = note.Id;
        showNoteForm = false;
        editingNote = new TreatmentNote
        {
            Id = note.Id,
            PetId = note.PetId,
            Date = note.Date,
            Summary = note.Summary,
            Description = note.Description,
            Diagnosis = note.Diagnosis,
            Medication = note.Medication,
            Veterinarian = note.Veterinarian
        };
    }

    private void CancelNoteEdit()
    {
        editingNoteId = null;
        editingNote = new();
    }

    private async Task SaveNoteAsync()
    {
        editingNote.PetId = Id;
        await PatientService.SaveTreatmentNoteAsync(editingNote);
        editingNote = new();
        showNoteForm = false;
        editingNoteId = null;
        await LoadAsync();
    }

    private async Task DeleteNoteAsync(int id)
    {
        await PatientService.DeleteTreatmentNoteAsync(id);
        deleteConfirmNoteId = null;
        await LoadAsync();
    }

    private void ToggleNoteDetails(int noteId)
    {
        if (!expandedNoteIds.Remove(noteId))
            expandedNoteIds.Add(noteId);
    }

    protected override void OnParametersSet()
    {
        if (pet != null)
        {
            editingPet = new Pet
            {
                Id = pet.Id,
                Name = pet.Name,
                Species = pet.Species,
                Breed = pet.Breed,
                DateOfBirth = pet.DateOfBirth,
                WeightKg = pet.WeightKg,
                Color = pet.Color,
                Sex = pet.Sex,
                MicrochipId = pet.MicrochipId,
                OwnerId = pet.OwnerId
            };
        }
    }

    private string CalculateAge(DateOnly? dob)
    {
        if (dob is null) return "—";
        var today = DateOnly.FromDateTime(DateTime.Today);
        var age = today.Year - dob.Value.Year;
        if (dob.Value.AddYears(age) > today) age--;
        return age < 1 ? "< 1 yr" : $"{age} yr";
    }
}

