                            <InputDate class="form-control" @bind-Value="newPet.DateOfBirth" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Weight (kg)</label>
                            <InputNumber class="form-control" @bind-Value="newPet.WeightKg" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Color</label>
                            <InputText class="form-control" @bind-Value="newPet.Color" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Sex</label>
