                            <button type="submit" class="btn btn-success btn-sm me-1">Save</button>
                            <button type="button" class="btn btn-secondary btn-sm" @onclick="TogglePetForm">Cancel</button>
                        </div>
                    </div>
                </EditForm>
            </div>
        </div>
    }

    @if (owner.Pets.Count == 0 && !showPetForm)
    {
        <p class="text-muted">No pets registered for this owner.</p>
    }
    else if (owner.Pets.Count > 0)
    {
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Name</th>
                    <th>Species</th>
                    <th>Breed</th>
                </tr>
