    private Owner? owner;
    private bool editMode;
    private Owner editingOwner = new();
    private bool showPetForm;
    private Pet newPet = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        owner = await PatientService.GetOwnerAsync(Id);
        if (owner != null)
        {
            editingOwner = new Owner
            {
                Id = owner.Id,
                FirstName = owner.FirstName,
                LastName = owner.LastName,
                Phone = owner.Phone,
                Email = owner.Email,
                Address = owner.Address
            };
        }
    }

    private void CancelEdit()
    {
        editMode = false;
        if (owner != null)
        {
            editingOwner = new Owner
            {
                Id = owner.Id,
                FirstName = owner.FirstName,
                LastName = owner.LastName,
                Phone = owner.Phone,
                Email = owner.Email,
                Address = owner.Address
            };
        }
    }

    private async Task SaveOwnerAsync()
    {
        await PatientService.SaveOwnerAsync(editingOwner);
        editMode = false;
        await LoadAsync();
    }

    private void TogglePetForm()
    {
        showPetForm = !showPetForm;
        if (showPetForm)
        {
            newPet = new Pet { OwnerId = Id };
        }
        else
        {
            newPet = new();
        }
    }

    private async Task SavePetAsync()
    {
        newPet.OwnerId = Id;
        await PatientService.SavePetAsync(newPet);
        showPetForm = false;
        newPet = new();
        await LoadAsync();
    }
}

