     private bool loading = true;
     private int petCount;
     private int todayAppointments;
     private int weekAppointments;
     private int pendingInvoices;
     private List<Appointment> todayAppts = [];

     protected override async Task OnInitializedAsync()
     {
         var today = DateTime.Today;
         var weekStart = today.AddDays(-(int)today.DayOfWeek + (int)DayOfWeek.Monday);
         if (today.DayOfWeek == DayOfWeek.Sunday) weekStart = weekStart.AddDays(-7);
         var weekEnd = weekStart.AddDays(7);

         var pets = await PatientService.GetPetsAsync(null);
         petCount = pets.Count;

         todayAppts = await AppointmentService.GetAppointmentsAsync(today, today.AddDays(1));
         todayAppointments = todayAppts.Count(a => a.Status != AppointmentStatus.Cancelled);

         var weekAppts = await AppointmentService.GetAppointmentsAsync(weekStart, weekEnd);
         weekAppointments = weekAppts.Count(a => a.Status != AppointmentStatus.Cancelled);

         var invoices = await BillingService.GetInvoicesAsync(null, InvoiceStatus.Pending);
         pendingInvoices = invoices.Count;

         todayAppts = todayAppts.Where(a => a.Status != AppointmentStatus.Cancelled).OrderBy(a => a.StartTime).ToList();
         loading = false;
     }
 }

