@* ────────── Calendar Grid ────────── *@
@if (loading)
{
    <p><em>Loading appointments…</em></p>
}
else
{
    <div class="table-responsive">
        <table class="table table-bordered table-sm" style="table-layout:fixed;">
            <thead class="table-light" style="position:sticky; top:0; z-index:10;">
                <tr>
                    <th style="width:80px;">Time</th>
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var isToday = day.Date == DateTime.Today;
                        <th class="text-center @(isToday ? "table-info" : "")">
                            @day.ToString("ddd M/d")
                        </th>
                    }
                </tr>
            </thead>
            <tbody>
                @foreach (var slotTime in timeSlots)
                {
                    <tr>
                        <td class="text-nowrap text-muted small">@slotTime.ToString("h:mm tt")</td>
                        @for (int d = 0; d < 7; d++)
                        {
                            var day = weekStart.AddDays(d);
                            var slotStart = day.Date.Add(slotTime);
                            var slotEnd = slotStart.AddMinutes(30);
                            var appts = GetAppointmentsForSlot(slotStart, slotEnd);

                            <td class="p-0" style="vertical-align:top; min-height:30px;">
                                @foreach (var a in appts)
                                {
                                    var bgClass = a.Status switch
                                    {
                                        AppointmentStatus.Scheduled => "bg-primary",
                                        AppointmentStatus.Completed => "bg-success",
                                        _ => "bg-secondary"
                                    };
