}

@* ────────── Appointment Detail Panel ────────── *@
@if (selectedAppointment is not null)
{
    <div class="card mt-3 border-info">
        <div class="card-header bg-info text-white d-flex justify-content-between align-items-center">
            <strong>Appointment Details</strong>
            <button class="btn btn-sm btn-light" @onclick="() => selectedAppointment = null">&times;</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Pet</dt>
                        <dd class="col-sm-8">@(selectedAppointment.Pet?.Name ?? "—")</dd>

                        <dt class="col-sm-4">Owner</dt>
                        <dd class="col-sm-8">@(selectedAppointment.Pet?.Owner?.FullName ?? "—")</dd>

                        <dt class="col-sm-4">Date / Time</dt>
                        <dd class="col-sm-8">@selectedAppointment.StartTime.ToString("MMM d, yyyy h:mm tt")</dd>

                        <dt class="col-sm-4">Duration</dt>
                        <dd class="col-sm-8">@selectedAppointment.DurationMinutes min</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Reason</dt>
                        <dd class="col-sm-8">@selectedAppointment.Reason</dd>

                        <dt class="col-sm-4">Veterinarian</dt>
                        <dd class="col-sm-8">@selectedAppointment.Veterinarian</dd>

                        <dt class="col-sm-4">Status</dt>
                        <dd class="col-sm-8">
                            <span class="badge @StatusBadge(selectedAppointment.Status)">@selectedAppointment.Status</span>
                        </dd>

                        <dt class="col-sm-4">Notes</dt>
                        <dd class="col-sm-8">@(selectedAppointment.Notes ?? "—")</dd>
                    </dl>
                </div>
            </div>

            @if (!string.IsNullOrEmpty(detailError))
            {
                <div class="alert alert-danger mt-2">@detailError</div>
            }

            <div class="mt-3 d-flex gap-2 flex-wrap">
                @if (selectedAppointment.Status == AppointmentStatus.Scheduled)
                {
                    <button class="btn btn-warning btn-sm" @onclick="StartReschedule">Reschedule</button>
                    <button class="btn btn-success btn-sm" @onclick="MarkComplete">Mark Complete</button>
                }
                @if (selectedAppointment.Status == AppointmentStatus.Scheduled)
                {
                    if (!confirmingCancel)
                    {
                        <button class="btn btn-danger btn-sm" @onclick="() => confirmingCancel = true">Cancel Appointment</button>
                    }
                    else
                    {
                        <span class="text-danger fw-bold me-2">Are you sure?</span>
                        <button class="btn btn-danger btn-sm" @onclick="ConfirmCancel">Yes, Cancel</button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="() => confirmingCancel = false">No</button>
                    }
                }
            </div>

            @* Reschedule sub-panel *@
            @if (showReschedule)
            {
                <div class="border rounded p-3 mt-3 bg-light">
                    <h6>Reschedule Appointment</h6>
                    <div class="row g-2 align-items-end">
                        <div class="col-auto">
                            <label class="form-label">New Date</label>
                            <input type="date" class="form-control"
                                   value="@rescheduleDate?.ToString("yyyy-MM-dd")"
                                   @onchange="OnRescheduleDateChanged" />
                        </div>
                    </div>
                    @if (loadingRescheduleSlots)
                    {
                        <p class="text-muted mt-2"><em>Loading slots…</em></p>
                    }
                    else if (rescheduleSlots is { Count: > 0 })
                    {
                        <div class="mt-2 d-flex flex-wrap gap-2">
                            @foreach (var slot in rescheduleSlots)
                            {
                                var isSelected = rescheduleSelectedSlot == slot;
                                <button class="btn btn-sm @(isSelected ? "btn-primary" : "btn-outline-primary")"
                                        @onclick="() => rescheduleSelectedSlot = slot">
                                    @slot.ToString("h:mm tt")
                                </button>
                            }
                        </div>
                        @if (rescheduleSelectedSlot.HasValue)
                        {
                            <button class="btn btn-success btn-sm mt-2" @onclick="ConfirmReschedule" disabled="@saving">
                                @(saving ? "Saving…" : "Confirm Reschedule")
                            </button>
                        }
                    }
                    else if (rescheduleDate.HasValue)
                    {
                        <p class="text-muted mt-2">No available slots on this date.</p>
                    }
                    <button class="btn btn-outline-secondary btn-sm mt-2 ms-2" @onclick="() => showReschedule = false">Cancel</button>
                </div>
            }
        </div>
    </div>
}

@code {
    // ── Data ──
    private List<Appointment> appointments = new();
    private List<string> veterinarians = new();
    private List<Pet> allPets = new();

    // ── Calendar state ──
    private DateTime weekStart;
    private string vetFilter = "";
    private bool loading = true;

    // ── Time slots (8:00 AM – 4:30 PM in 30-min increments) ──
    private static readonly List<TimeSpan> timeSlots = Enumerable.Range(0, 18)
        .Select(i => TimeSpan.FromHours(8) + TimeSpan.FromMinutes(i * 30))
        .ToList();

    // ── Detail panel ──
    private Appointment? selectedAppointment;
    private bool confirmingCancel;
    private string detailError = "";

    // ── Reschedule ──
    private bool showReschedule;
    private DateTime? rescheduleDate;
    private List<DateTime>? rescheduleSlots;
    private DateTime? rescheduleSelectedSlot;
    private bool loadingRescheduleSlots;

    // ── New appointment form ──
    private bool showNewForm;
    private Appointment newAppt = new() { DurationMinutes = 30 };
    private DateTime? newApptDate;
    private List<DateTime>? availableSlots;
    private bool loadingSlots;
    private bool saving;
    private string formError = "";
    private string petSearchText = "";
    private bool showPetDropdown;
    private Pet? selectedPet;

    private List<Pet>? filteredPets => string.IsNullOrWhiteSpace(petSearchText)
        ? allPets
        : allPets.Where(p =>
            p.Name.Contains(petSearchText, StringComparison.OrdinalIgnoreCase) ||
            (p.Owner?.FullName ?? "").Contains(petSearchText, StringComparison.OrdinalIgnoreCase))
          .ToList();

    // ── Lifecycle ──
    protected override async Task OnInitializedAsync()
    {
        weekStart = GetMonday(DateTime.Today);
        veterinarians = await AppointmentService.GetVeterinariansAsync();
        allPets = await PatientService.GetPetsAsync(null);
        await LoadAppointments();
    }

    // ── Navigation ──
    private async Task PrevWeek() { weekStart = weekStart.AddDays(-7); await LoadAppointments(); }
    private async Task NextWeek() { weekStart = weekStart.AddDays(7); await LoadAppointments(); }
    private async Task GoToday() { weekStart = GetMonday(DateTime.Today); await LoadAppointments(); }

    private async Task LoadAppointments()
    {
        loading = true;
        selectedAppointment = null;
        var end = weekStart.AddDays(7);
        var all = await AppointmentService.GetAppointmentsAsync(weekStart, end);
        if (!string.IsNullOrEmpty(vetFilter))
            all = all.Where(a => a.Veterinarian == vetFilter).ToList();
        appointments = all.ToList();
        loading = false;
    }

    // ── Calendar helpers ──
    private List<Appointment> GetAppointmentsForSlot(DateTime slotStart, DateTime slotEnd)
    {
        return appointments
            .Where(a => a.StartTime < slotEnd && a.EndTime > slotStart)
            .ToList();
    }

    private static DateTime GetMonday(DateTime date)
    {
        var diff = (7 + (date.DayOfWeek - DayOfWeek.Monday)) % 7;
        return date.AddDays(-diff).Date;
    }

    private static string StatusBadge(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        _ => "bg-secondary"
    };

    private static string TruncateText(string text, int max) =>
        text.Length <= max ? text : text[..max] + "…";

    // ── Detail panel ──
    private void SelectAppointment(Appointment a)
    {
        selectedAppointment = a;
        confirmingCancel = false;
        showReschedule = false;
        detailError = "";
    }

    private async Task MarkComplete()
    {
        if (selectedAppointment is null) return;
        detailError = "";
        try
        {
            selectedAppointment.Status = AppointmentStatus.Completed;
            await AppointmentService.SaveAppointmentAsync(selectedAppointment);
            await LoadAppointments();
            selectedAppointment = appointments.FirstOrDefault(a => a.Id == selectedAppointment.Id);
        }
        catch (InvalidOperationException ex)
        {
            detailError = ex.Message;
        }
    }

    private async Task ConfirmCancel()
    {
        if (selectedAppointment is null) return;
        detailError = "";
        await AppointmentService.CancelAppointmentAsync(selectedAppointment.Id);
        confirmingCancel = false;
        var id = selectedAppointment.Id;
        await LoadAppointments();
        selectedAppointment = appointments.FirstOrDefault(a => a.Id == id);
    }

    // ── Reschedule ──
    private void StartReschedule()
    {
        showReschedule = true;
        rescheduleDate = null;
        rescheduleSlots = null;
        rescheduleSelectedSlot = null;
    }

    private async Task OnRescheduleDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var d))
        {
            rescheduleDate = d;
            rescheduleSelectedSlot = null;
            loadingRescheduleSlots = true;
            rescheduleSlots = await AppointmentService.GetAvailableSlotsAsync(
                d, selectedAppointment!.Veterinarian, selectedAppointment.DurationMinutes);
            loadingRescheduleSlots = false;
        }
    }

    private async Task ConfirmReschedule()
    {
        if (selectedAppointment is null || !rescheduleSelectedSlot.HasValue) return;
        saving = true;
        detailError = "";
        try
        {
            selectedAppointment.StartTime = rescheduleSelectedSlot.Value;
            await AppointmentService.SaveAppointmentAsync(selectedAppointment);
            showReschedule = false;
            var id = selectedAppointment.Id;
            await LoadAppointments();
            selectedAppointment = appointments.FirstOrDefault(a => a.Id == id);
        }
        catch (InvalidOperationException ex)
        {
            detailError = ex.Message;
        }
        finally { saving = false; }
    }

    // ── New Appointment ──
    private void SelectPet(Pet p)
    {
        selectedPet = p;
        newAppt.PetId = p.Id;
        petSearchText = $"{p.Name} ({p.Owner?.FullName ?? "—"})";
        showPetDropdown = false;
    }

    private async Task OnNewApptDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var d))
        {
            newApptDate = d;
            await LoadNewSlots();
        }
    }

    private async Task OnNewSlotParamsChanged()
    {
        if (newApptDate.HasValue && !string.IsNullOrEmpty(newAppt.Veterinarian))
            await LoadNewSlots();
    }

    private async Task LoadNewSlots()
    {
        if (!newApptDate.HasValue || string.IsNullOrEmpty(newAppt.Veterinarian)) return;
        loadingSlots = true;
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(
            newApptDate.Value, newAppt.Veterinarian, newAppt.DurationMinutes);
        loadingSlots = false;
    }

    private async Task SaveNewAppointment()
    {
        formError = "";
        if (newAppt.PetId == 0) { formError = "Please select a pet."; return; }
        if (string.IsNullOrEmpty(newAppt.Veterinarian)) { formError = "Please select a veterinarian."; return; }
        if (newAppt.StartTime == default) { formError = "Please select a time slot."; return; }
        if (string.IsNullOrWhiteSpace(newAppt.Reason)) { formError = "Please enter a reason."; return; }

        saving = true;
        try
        {
            newAppt.Status = AppointmentStatus.Scheduled;
            await AppointmentService.SaveAppointmentAsync(newAppt);
            showNewForm = false;
            ResetNewForm();
            await LoadAppointments();
        }
        catch (InvalidOperationException ex)
        {
            formError = ex.Message;
        }
        finally { saving = false; }
    }

    private void ResetNewForm()
    {
        newAppt = new Appointment { DurationMinutes = 30 };
        newApptDate = null;
        availableSlots = null;
        petSearchText = "";
        selectedPet = null;
        formError = "";
    }
}

