+                            <span class="badge @StatusBadge(selectedAppointment.Status)">@selectedAppointment.Status</span>
+                        </dd>
+
+                        <dt class="col-sm-4">Notes</dt>
+                        <dd class="col-sm-8">@(selectedAppointment.Notes ?? "—")</dd>
