+
+            <div class="mt-3 d-flex gap-2 flex-wrap">
+                @if (selectedAppointment.Status == AppointmentStatus.Scheduled)
+                {
+                    <button class="btn btn-warning btn-sm" @onclick="StartReschedule">Reschedule</button>
+                    <button class="btn btn-success btn-sm" @onclick="MarkComplete">Mark Complete</button>
+                }
+                @if (selectedAppointment.Status == AppointmentStatus.Scheduled)
+                {
+                    if (!confirmingCancel)
+                    {
+                        <button class="btn btn-danger btn-sm" @onclick="() => confirmingCancel = true">Cancel Appointment</button>
+                    }
+                    else
+                    {
+                        <span class="text-danger fw-bold me-2">Are you sure?</span>
+                        <button class="btn btn-danger btn-sm" @onclick="ConfirmCancel">Yes, Cancel</button>
+                        <button class="btn btn-outline-secondary btn-sm" @onclick="() => confirmingCancel = false">No</button>
+                    }
+                }
+            </div>
+
+            @* Reschedule sub-panel *@
+            @if (showReschedule)
+            {
+                <div class="border rounded p-3 mt-3 bg-light">
+                    <h6>Reschedule Appointment</h6>
+                    <div class="row g-2 align-items-end">
+                        <div class="col-auto">
+                            <label class="form-label">New Date</label>
+                            <input type="date" class="form-control"
+                                   value="@rescheduleDate?.ToString("yyyy-MM-dd")"
+                                   @onchange="OnRescheduleDateChanged" />
+                        </div>
+                    </div>
+                    @if (loadingRescheduleSlots)
+                    {
+                        <p class="text-muted mt-2"><em>Loading slots…</em></p>
+                    }
+                    else if (rescheduleSlots is { Count: > 0 })
+                    {
+                        <div class="mt-2 d-flex flex-wrap gap-2">
+                            @foreach (var slot in rescheduleSlots)
+                            {
+                                var isSelected = rescheduleSelectedSlot == slot;
+                                <button class="btn btn-sm @(isSelected ? "btn-primary" : "btn-outline-primary")"
+                                        @onclick="() => rescheduleSelectedSlot = slot">
+                                    @slot.ToString("h:mm tt")
+                                </button>
+                            }
+                        </div>
+                        @if (rescheduleSelectedSlot.HasValue)
+                        {
+                            <button class="btn btn-success btn-sm mt-2" @onclick="ConfirmReschedule" disabled="@saving">
+                                @(saving ? "Saving…" : "Confirm Reschedule")
+                            </button>
