+        availableSlots = await AppointmentService.GetAvailableSlotsAsync(
+            newApptDate.Value, newAppt.Veterinarian, newAppt.DurationMinutes);
+        loadingSlots = false;
+    }
+
+    private async Task SaveNewAppointment()
+    {
+        formError = "";
+        if (newAppt.PetId == 0) { formError = "Please select a pet."; return; }
+        if (string.IsNullOrEmpty(newAppt.Veterinarian)) { formError = "Please select a veterinarian."; return; }
+        if (newAppt.StartTime == default) { formError = "Please select a time slot."; return; }
+        if (string.IsNullOrWhiteSpace(newAppt.Reason)) { formError = "Please enter a reason."; return; }
+
+        saving = true;
+        try
+        {
+            newAppt.Status = AppointmentStatus.Scheduled;
+            await AppointmentService.SaveAppointmentAsync(newAppt);
+            showNewForm = false;
+            ResetNewForm();
+            await LoadAppointments();
+        }
+        catch (InvalidOperationException ex)
+        {
+            formError = ex.Message;
+        }
+        finally { saving = false; }
+    }
+
+    private void ResetNewForm()
+    {
+        newAppt = new Appointment { DurationMinutes = 30 };
+        newApptDate = null;
+        availableSlots = null;
+        petSearchText = "";
+        selectedPet = null;
+        formError = "";
+    }
+}
