@page "/billing"
@rendermode InteractiveServer
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services

@inject BillingService BillingService
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Billing</PageTitle>

<h1 class="mb-4">💳 Billing</h1>

@if (loading)
{
    <p>Loading invoices...</p>
}
else
{
    <!-- Summary Cards -->
    <div class="row g-3 mb-4">
        <div class="col-md-3">
            <div class="card text-bg-warning">
                <div class="card-body">
                    <h6 class="card-title">Total Outstanding</h6>
                    <p class="card-text display-6">@totalOutstanding.ToString("C")</p>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-danger">
                <div class="card-body">
                    <h6 class="card-title">Total Overdue</h6>
                    <p class="card-text display-6">@totalOverdue.ToString("C")</p>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-success">
                <div class="card-body">
                    <h6 class="card-title">Paid This Month</h6>
                    <p class="card-text display-6">@paidThisMonth.ToString("C")</p>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-primary">
                <div class="card-body">
                    <h6 class="card-title">Invoice Count</h6>
                    <p class="card-text display-6">@invoices.Count</p>
                </div>
            </div>
        </div>
    </div>

    <!-- Top Bar -->
    <div class="d-flex gap-2 mb-3">
        <input type="text" class="form-control" placeholder="Search invoices..." value="@searchTerm"
               @oninput="OnSearchChanged" style="max-width: 300px;" />
        <select class="form-select" style="max-width: 200px;" value="@selectedStatus" @onchange="OnStatusChanged">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<InvoiceStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
        <button class="btn btn-primary ms-auto" @onclick="ToggleCreateForm">
            <i class="bi bi-plus-lg"></i> Create Invoice
        </button>
    </div>

    <!-- Create Invoice Form -->
    @if (showCreateForm)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5 class="card-title">Create New Invoice</h5>
                <div class="mb-3 position-relative">
                    <label class="form-label">Select Pet</label>
                    <input type="text" class="form-control" placeholder="Search pets..."
                           value="@petSearchTerm" @oninput="OnPetSearchChanged" />
                    @if (petResults.Count > 0 && !petSelected)
                    {
                        <ul class="list-group position-absolute w-100" style="z-index: 1000; max-height: 200px; overflow-y: auto;">
                            @foreach (var pet in petResults)
                            {
                                <li class="list-group-item list-group-item-action" style="cursor: pointer;"
                                    @onclick="() => SelectPet(pet)">
                                    @pet.Name (@pet.Owner.FirstName @pet.Owner.LastName)
                                </li>
                            }
                        </ul>
                    }
                </div>
                @if (selectedPet is not null)
                {
                    <div class="alert alert-info py-2">
                        Selected: <strong>@selectedPet.Name</strong> — Owner: @selectedPet.Owner.FirstName @selectedPet.Owner.LastName
                    </div>
                }
                <div class="d-flex gap-2">
                    <button class="btn btn-success" @onclick="CreateInvoice" disabled="@(selectedPet is null || creating)">
                        @(creating ? "Creating..." : "Create Invoice")
                    </button>
                    <button class="btn btn-secondary" @onclick="ToggleCreateForm">Cancel</button>
                </div>
            </div>
        </div>
    }

    <!-- Invoice Table -->
    <div class="table-responsive">
        <table class="table table-hover">
            <thead class="table-light">
                <tr>
                    <th>Invoice #</th>
                    <th>Pet</th>
                    <th>Owner</th>
                    <th>Date</th>
                    <th>Total</th>
                    <th>Paid</th>
                    <th>Balance</th>
                    <th>Status</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @if (invoices.Count == 0)
                {
                    <tr><td colspan="9" class="text-muted text-center">No invoices found.</td></tr>
                }
                else
                {
                    @foreach (var inv in invoices)
                    {
                        <tr style="cursor: pointer;" @onclick="() => NavigateToInvoice(inv.Id)">
                            <td>@inv.InvoiceNumber</td>
                            <td>@inv.Pet.Name</td>
                            <td>@inv.Pet.Owner.FirstName @inv.Pet.Owner.LastName</td>
                            <td>@inv.CreatedDate.ToString("MMM dd, yyyy")</td>
                            <td>@inv.Total.ToString("C")</td>
                            <td>@inv.AmountPaid.ToString("C")</td>
                            <td>@inv.Balance.ToString("C")</td>
                            <td><span class="badge bg-@GetStatusColor(inv.Status)">@inv.Status</span></td>
                            <td>
                                <a href="billing/@inv.Id" class="btn btn-sm btn-outline-primary" @onclick:stopPropagation="true">View</a>
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>
}

@code {
    private bool loading = true;
    private List<Invoice> invoices = [];
    private string searchTerm = "";
    private string selectedStatus = "";

    private bool showCreateForm;
    private string petSearchTerm = "";
    private List<Pet> petResults = [];
    private Pet? selectedPet;
    private bool petSelected;
    private bool creating;

    private decimal totalOutstanding;
    private decimal totalOverdue;
    private decimal paidThisMonth;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        loading = true;
        InvoiceStatus? status = string.IsNullOrEmpty(selectedStatus) ? null : Enum.Parse<InvoiceStatus>(selectedStatus);
        invoices = await BillingService.GetInvoicesAsync(
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm, status);

        var allInvoices = await BillingService.GetInvoicesAsync();
        totalOutstanding = allInvoices
            .Where(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.Overdue)
            .Sum(i => i.Balance);
        totalOverdue = allInvoices
            .Where(i => i.Status == InvoiceStatus.Overdue)
            .Sum(i => i.Balance);

        var monthStart = new DateTime(DateTime.UtcNow.Year, DateTime.UtcNow.Month, 1);
        paidThisMonth = allInvoices
            .Where(i => i.Status == InvoiceStatus.Paid && i.CreatedDate >= monthStart)
            .Sum(i => i.AmountPaid);

        loading = false;
    }

    private async Task OnSearchChanged(ChangeEventArgs e)
    {
        searchTerm = e.Value?.ToString() ?? "";
        await LoadInvoices();
    }

    private async Task OnStatusChanged(ChangeEventArgs e)
    {
        selectedStatus = e.Value?.ToString() ?? "";
        await LoadInvoices();
    }

    private void ToggleCreateForm()
    {
        showCreateForm = !showCreateForm;
        petSearchTerm = "";
        petResults = [];
        selectedPet = null;
        petSelected = false;
    }

    private async Task OnPetSearchChanged(ChangeEventArgs e)
    {
        petSearchTerm = e.Value?.ToString() ?? "";
        petSelected = false;
        if (string.IsNullOrWhiteSpace(petSearchTerm))
        {
            petResults = [];
            selectedPet = null;
        }
        else
        {
            petResults = await PatientService.GetPetsAsync(petSearchTerm);
        }
    }

    private void SelectPet(Pet pet)
    {
        selectedPet = pet;
        petSearchTerm = $"{pet.Name} ({pet.Owner.FirstName} {pet.Owner.LastName})";
        petSelected = true;
        petResults = [];
    }

    private async Task CreateInvoice()
    {
        if (selectedPet is null) return;
        creating = true;
        var invoice = new Invoice { PetId = selectedPet.Id };
        await BillingService.CreateInvoiceAsync(invoice);
        creating = false;
        Navigation.NavigateTo($"billing/{invoice.Id}");
    }

    private void NavigateToInvoice(int id)
    {
        Navigation.NavigateTo($"billing/{id}");
    }

    private static string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "secondary",
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Overdue => "danger",
        InvoiceStatus.Cancelled => "dark",
        _ => "secondary"
    };
}

@page "/billing/{Id:int}"
@rendermode InteractiveServer
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
