                    </div>
                </div>
                <div class="col-md-4">
                    <div class="border rounded p-3 text-center">
                        <small class="text-muted">Balance</small>
                        <div class="fw-bold fs-5 text-danger">@invoice.Balance.ToString("C")</div>
                    </div>
