@code {
    private bool loading = true;
    private List<Invoice> invoices = [];
    private string searchTerm = "";
    private string selectedStatus = "";

    private bool showCreateForm;
    private string petSearchTerm = "";
    private List<Pet> petResults = [];
    private Pet? selectedPet;
    private bool petSelected;
    private bool creating;

    private decimal totalOutstanding;
    private decimal totalOverdue;
    private decimal paidThisMonth;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        loading = true;
        InvoiceStatus? status = string.IsNullOrEmpty(selectedStatus) ? null : Enum.Parse<InvoiceStatus>(selectedStatus);
        invoices = await BillingService.GetInvoicesAsync(
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm, status);

        var allInvoices = await BillingService.GetInvoicesAsync();
        totalOutstanding = allInvoices
            .Where(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.Overdue)
            .Sum(i => i.Balance);
        totalOverdue = allInvoices
            .Where(i => i.Status == InvoiceStatus.Overdue)
            .Sum(i => i.Balance);

        var monthStart = new DateTime(DateTime.UtcNow.Year, DateTime.UtcNow.Month, 1);
        paidThisMonth = allInvoices
            .Where(i => i.Status == InvoiceStatus.Paid && i.CreatedDate >= monthStart)
            .Sum(i => i.AmountPaid);

        loading = false;
    }

    private async Task OnSearchChanged(ChangeEventArgs e)
    {
        searchTerm = e.Value?.ToString() ?? "";
        await LoadInvoices();
    }

    private async Task OnStatusChanged(ChangeEventArgs e)
    {
        selectedStatus = e.Value?.ToString() ?? "";
        await LoadInvoices();
    }

    private void ToggleCreateForm()
    {
        showCreateForm = !showCreateForm;
        petSearchTerm = "";
        petResults = [];
        selectedPet = null;
        petSelected = false;
    }

    private async Task OnPetSearchChanged(ChangeEventArgs e)
    {
        petSearchTerm = e.Value?.ToString() ?? "";
        petSelected = false;
        if (string.IsNullOrWhiteSpace(petSearchTerm))
        {
            petResults = [];
            selectedPet = null;
        }
        else
        {
            petResults = await PatientService.GetPetsAsync(petSearchTerm);
        }
    }

    private void SelectPet(Pet pet)
    {
        selectedPet = pet;
        petSearchTerm = $"{pet.Name} ({pet.Owner.FirstName} {pet.Owner.LastName})";
        petSelected = true;
        petResults = [];
    }

    private async Task CreateInvoice()
    {
        if (selectedPet is null) return;
        creating = true;
        var invoice = new Invoice { PetId = selectedPet.Id };
        await BillingService.CreateInvoiceAsync(invoice);
        creating = false;
        Navigation.NavigateTo($"billing/{invoice.Id}");
    }

    private void NavigateToInvoice(int id)
    {
        Navigation.NavigateTo($"billing/{id}");
    }

    private static string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "secondary",
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Overdue => "danger",
        InvoiceStatus.Cancelled => "dark",
        _ => "secondary"
    };
}

