                        </div>
                        <div class="mt-2 d-flex gap-2">
                            <button type="submit" class="btn btn-success" disabled="@processingPayment">
                                @(processingPayment ? "Processing..." : "Submit Payment")
                            </button>
                            <button type="button" class="btn btn-secondary" @onclick="TogglePaymentForm">Cancel</button>
                        </div>
                    </EditForm>
                </div>
            }

            <!-- Payment History -->
            @if (payments.Count > 0)
            {
                <table class="table table-sm">
                    <thead class="table-light">
                        <tr>
                            <th>Date</th>
                            <th>Amount</th>
                            <th>Method</th>
                            <th>Reference</th>
                            <th>Status</th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var p in payments)
                        {
                            <tr>
                                <td>@p.Date.ToString("MMM dd, yyyy")</td>
                                <td>@p.Amount.ToString("C")</td>
                                <td>@p.Method</td>
                                <td>@(p.Reference ?? "—")</td>
                                <td>
                                    @if (p.Refunded)
                                    {
                                        <span class="badge bg-danger">Refunded</span>
                                    }
                                    else
                                    {
                                        <span class="badge bg-success">Completed</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
            else
            {
                <p class="text-muted mb-0">No payments recorded yet.</p>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private bool loading = true;
    private Invoice? invoice;
    private List<Payment> payments = [];

    private InvoiceItem newItem = new() { Quantity = 1 };
    private bool showPaymentForm;
    private Payment newPayment = new();
    private bool processingPayment;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        loading = true;
        invoice = await BillingService.GetInvoiceAsync(Id);
        if (invoice is not null)
        {
            payments = await BillingService.GetPaymentHistoryAsync(Id);
        }
        loading = false;
    }

    private async Task AddItem()
    {
        if (invoice is null || string.IsNullOrWhiteSpace(newItem.Description)) return;
        newItem.InvoiceId = invoice.Id;
        await BillingService.AddInvoiceItemAsync(newItem);
        newItem = new InvoiceItem { Quantity = 1 };
        await LoadInvoice();
    }

    private async Task RemoveItem(int itemId)
    {
        await BillingService.RemoveInvoiceItemAsync(itemId);
        await LoadInvoice();
    }

    private void TogglePaymentForm()
    {
        showPaymentForm = !showPaymentForm;
        if (showPaymentForm && invoice is not null)
        {
            newPayment = new Payment
            {
                InvoiceId = invoice.Id,
                Amount = invoice.Balance,
                Date = DateTime.UtcNow
            };
        }
    }

    private async Task SubmitPayment()
    {
        if (invoice is null) return;
        processingPayment = true;
        newPayment.InvoiceId = invoice.Id;
        await BillingService.ProcessPaymentAsync(newPayment);
        showPaymentForm = false;
        processingPayment = false;
        newPayment = new Payment();
        await LoadInvoice();
    }

    private async Task SendInvoice()
    {
        if (invoice is null) return;
        invoice.Status = InvoiceStatus.Pending;
        await BillingService.UpdateInvoiceAsync(invoice);
        await LoadInvoice();
    }

    private async Task CancelInvoice()
    {
        if (invoice is null) return;
        invoice.Status = InvoiceStatus.Cancelled;
        await BillingService.UpdateInvoiceAsync(invoice);
        await LoadInvoice();
    }

    private static string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "secondary",
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Overdue => "danger",
        InvoiceStatus.Cancelled => "dark",
        _ => "secondary"
    };
}

